1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_COUNT_FOR_REPRODUCTION = 3;
4	const NEIGHBOR_COUNT_FOR_SURVIVAL = 2;
5	
6	const NEIGHBOR_OFFSETS: Cell[] = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1, 0], [1, 0],
9	  [-1, 1], [0, 1], [1, 1],
10	];
11	
12	function toKey([x, y]: Cell): string {
13	  return `${x},${y}`;
14	}
15	
16	function fromKey(key: string): Cell {
17	  const [x, y] = key.split(",").map(Number);
18	  return [x, y];
19	}
20	
21	function neighborsOf([x, y]: Cell): Cell[] {
22	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
23	}
24	
25	function candidateCells(cells: Cell[]): Set<string> {
26	  const cellAndNeighbors = (cell: Cell): Cell[] => [cell, ...neighborsOf(cell)];
27	  return new Set(cells.flatMap(cellAndNeighbors).map(toKey));
28	}
29	
30	function countLiveNeighbors(cell: Cell, living: Set<string>): number {
31	  return neighborsOf(cell).filter((neighbor) => living.has(toKey(neighbor)))
32	    .length;
33	}
34	
35	function isBorn(liveNeighbors: number): boolean {
36	  return liveNeighbors === NEIGHBOR_COUNT_FOR_REPRODUCTION;
37	}
38	
39	function survives(isAlive: boolean, liveNeighbors: number): boolean {
40	  return isAlive && liveNeighbors === NEIGHBOR_COUNT_FOR_SURVIVAL;
41	}
42	
43	function survivesOrIsBorn(cell: Cell, living: Set<string>): boolean {
44	  const liveNeighbors = countLiveNeighbors(cell, living);
45	  const isAlive = living.has(toKey(cell));
46	  return isBorn(liveNeighbors) || survives(isAlive, liveNeighbors);
47	}
48	
49	export function nextGeneration(cells: Cell[]): Cell[] {
50	  const living = new Set(cells.map(toKey));
51	  return [...candidateCells(cells)]
52	    .map(fromKey)
53	    .filter((cell) => survivesOrIsBorn(cell, living));
54	}
