1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  // Simplest cases
6	  it("an empty grid stays empty — [] → []", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("a single live cell dies from underpopulation — [(0,0)] → []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  // Rule 1 - Underpopulation (live cell with < 2 neighbors dies)
14	  it("two adjacent live cells both die — [(0,1),(1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	
18	  // Rule 2 - Survival (live cell with 2 or 3 neighbors lives on)
19	  it("a live cell with exactly 3 live neighbors survives — (1,1) lives on", () => {
20	    // live cells: top row (0,0),(1,0),(2,0) plus center (1,1).
21	    // (1,1) has exactly 3 live neighbors (the top row) → survives.
22	    const next = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
23	    expect(next).toContainEqual([1, 1]);
24	  });
25	
26	  // Rule 3 - Overpopulation (live cell with > 3 neighbors dies)
27	  it("a live cell with more than 3 live neighbors dies — center (1,1) of ### / .#. / ### dies", () => {
28	    // live cells: ### / .#. / ### → (1,1) has 6 live neighbors → overpopulation.
29	    const next = nextGeneration([
30	      [0, 0], [1, 0], [2, 0],
31	      [1, 1],
32	      [0, 2], [1, 2], [2, 2],
33	    ]);
34	    expect(next).not.toContainEqual([1, 1]);
35	  });
36	
37	  // Rule 4 - Reproduction (dead cell with exactly 3 neighbors becomes alive)
38	  it("a dead cell with exactly 3 live neighbors becomes alive — (1,1) is born", () => {
39	    // live cells: ## / #.. → (0,0),(1,0),(0,1). Dead cell (1,1) has 3 live neighbors → born.
40	    const next = nextGeneration([[0, 0], [1, 0], [0, 1]]);
41	    expect(next).toContainEqual([1, 1]);
42	  });
43	
44	  // Pattern examples
45	  it("blinker oscillates — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
46	    const sortCells = (cells: [number, number][]) =>
47	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
48	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
49	    expect(sortCells(next)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
50	  });
51	  it("block is a still life — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
52	    const sortCells = (cells: [number, number][]) =>
53	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
54	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
55	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
56	  });
57	
58	  // Negative coordinates
59	  it.todo("handles negative coordinates correctly");
60	});
